#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <gmp.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    char buf[200];
    for(int tc=0; tc<T; ++tc){
        if(scanf("%s",buf)!=1) return 0;
        // use GMP for arbitrary length integer
        mpz_t y, ans;
        mpz_init_set_str(y, buf, 10);
        mpz_init(ans);
        if(mpz_cmp_ui(y,0)==0){
            mpz_set_ui(ans,1);
        }else{
            mpz_mul_ui(ans, y, 3);
        }
        gmp_printf("%Zd\n", ans);
        mpz_clear(y); mpz_clear(ans);
    }
    return 0;
}

